                                min="0"
                                step="0.01"
                            />
                        </label>
                        <label>
                            Department:
                            <input
                                type="text"
                                name="department"
                                value={formData.additionalFields?.department || ''}
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
