                                value={formData.additionalFields?.appointmentType || ''}
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                    </div>
                )}
                {formData.type === 'product' && (
                    <div>
                        <label>
                            Product Name:
                            <input
                                type="text"
                                name="productName"
                                value={formData.additionalFields?.productName || ''}
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
                            Product ID:
                            <input
                                type="text"
