                        </label>
                        <label>
                            Coverage (Region):
                            <input
                                type="text"
                                name="region"
                                value={formData.additionalFields?.region || ''}
                                onChange={handleAdditionalFieldsChange}
                                required
                            />
                        </label>
                        <label>
                            Phone Number:
                            <input
                                type="text"
                                name="phoneNumber"
                                value={formData.additionalFields?.phoneNumber || ''}
                                onChange={handleAdditionalFieldsChange}
                                required
